mapper.insert:
insert into ${tableName} (course_name, course_location, course_lecturer, course_date, course_week)
select #{course.courseName}, #{course.courseLocation}, #{course.courseLecturer}, #{course.courseDate}, #{course.courseWeek}
where not exists (select course_name from courses where course_name = #{course.courseName});

mapper.update:
update
${tableName} set
course_name = #{course.courseName}, course_location = #{course.courseLocation}, course_lecturer = #{course.courseLecturer}, course_date = #{course.courseDate}, course_week = #{course.courseWeek}
where course_name = #{course.courseName};

mapper.delete:
delete
from ${tableName}
where course_name like concat('%',#{courseName},'%');

mapper.select:
select course_name, course_location, course_lecturer, course_date, course_week
from ${tableName}
where course_name like concat('%',#{courseName},'%');

select course_name, course_location, course_lecturer, course_date, course_week
from ${tableName}
where course_date like concat('%',#{courseDate},'%');
